import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Routes } from '@angular/router';

import { CitComponent } from './cit/cit.component';
import { ITMComponent } from './itm/itm.component';
import { PSTComponent } from './pst/pst.component';



const routes: Routes = [{
  path: 'cit',
  component: CitComponent
}, {
  path: 'itm',
  component: ITMComponent
}, {
  path: 'pst',
  component: PSTComponent
}];

@NgModule({
  declarations: [],
  imports: [
    CommonModule,
    RouterModule.forChild(routes)
  ],
  exports: [RouterModule]
})
export class PACRoutingModule { }
